//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Level text & number format: lvlText %x substitution, numFmt, lvljc,
//! suff, isLgl".
//!
//! Each `#[test]` encodes a behavioral constraint mined from ECMA-376 /
//! ISO 29500-1 / MS-OI29500 about how Word *consumes* numbering-level
//! definitions (lvlText escape grammar, numFmt precedence, lvlJc supported
//! values, suff default, isLgl boolean, lvlOverride precedence). A FAIL here
//! encodes a real Word-compliance gap in the stemma engine: stemma either
//! rejects markup Word opens clean, or corrupts body text while resolving a
//! level. Do NOT weaken an assertion to make it pass — a fail is a finding.
//!
//! METHODOLOGY: all assertions here are CONSUMPTION-side (opens-clean validity
//! and accept-all body text). They never assert on re-serialized XML, because
//! stemma round-trips untouched numbering.xml byte-verbatim; "Word ignores
//! value V on render" is not "Word rewrites V on save", so an xmlOmits check on
//! a verbatim-preserved attribute would be a test-bug, not a gap.

use stemma::api::Document;

// ─── Prelude: minimal-.docx plumbing ─────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is the inner XML of `<w:body>`
/// (paragraphs + sectPr). `extra_parts` are additional package parts (e.g.
/// `word/numbering.xml`, `word/styles.xml`); each gets an `<Override>` in
/// `[Content_Types].xml` keyed off its part name, and a relationship from
/// `word/document.xml` so Word resolves it.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Map known part names to their WordprocessingML content type.
    fn content_type_for(part: &str) -> &'static str {
        match part {
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            other => panic!("make_docx: no content type registered for extra part {other:?}"),
        }
    }

    // Map known part names to their relationship type.
    fn rel_type_for(part: &str) -> &'static str {
        match part {
            "word/numbering.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
            }
            "word/styles.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
            }
            other => panic!("make_docx: no relationship type registered for extra part {other:?}"),
        }
    }

    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    let mut doc_rels = String::new();
    for (i, (part, _)) in extra_parts.iter().enumerate() {
        let part_name = if part.starts_with('/') {
            part.to_string()
        } else {
            format!("/{part}")
        };
        overrides.push_str(&format!(
            r#"<Override PartName="{part_name}" ContentType="{}"/>"#,
            content_type_for(part)
        ));
        // Relationship target is relative to word/ (the document part's folder).
        let target = part.strip_prefix("word/").unwrap_or(part);
        doc_rels.push_str(&format!(
            r#"<Relationship Id="rIdX{n}" Type="{ty}" Target="{target}"/>"#,
            n = i + 1,
            ty = rel_type_for(part),
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rels}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels_xml.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a string.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    use std::io::Read;
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse + re-serialize and return the resulting `word/document.xml`.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// Assert `validate` reports no errors, with a self-explanatory message.
fn assert_opens_clean(bytes: &[u8], rule: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{rule}\n  expected opens-clean (no validation issues) but got: {:?}",
        report.issues
    );
}

// ─── Specs ───────────────────────────────────────────────────────────────────

#[test]
fn lvltext_bare_percent_is_literal() {
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr/>"#;
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="0"><w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%1 100%"/><w:lvlJc w:val="left"/></w:lvl></w:abstractNum><w:num w:numId="1"><w:abstractNumId w:val="0"/></w:num></w:numbering>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.9.11 / MS-OI29500 §2.1.283: only '% followed by a number' is an escape; \
         a bare trailing '%' is literal text repeated each instance, so the file opens clean.",
    );
}

