#[test]
fn lvltext_percent_zero_is_literal_not_escape() {
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>Body alpha</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>Body beta</w:t></w:r></w:p><w:sectPr/>"#;
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="0"><w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%0."/><w:lvlJc w:val="start"/></w:lvl></w:abstractNum><w:num w:numId="1"><w:abstractNumId w:val="0"/></w:num></w:numbering>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);
    assert_opens_clean(
        &b,
        "ECMA-376 §17.9.11 / MS-OI29500 §2.1.283: lvlText@val=\"%0.\" is schema-valid ST_String \
         and %0 is not in Word's legal escape set %[1-9]; the package is well-formed and opens \
         without repair.",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted");
    assert_eq!(
        accepted.to_text().trim(),
        "Body alpha\n\nBody beta",
        "ECMA-376 §17.9.11: to_text() carries only run text (no synthesized marker), so accept-all \
         must reproduce the two run strings verbatim even though the level's lvlText contains the \
         non-escape token %0."
    );
}

#[test]
fn omitted_suff_element_defaults_to_tab_opens_clean() {
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>Item one</w:t></w:r></w:p><w:sectPr/>"#;
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="0"><w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%1."/><w:lvlJc w:val="start"/></w:lvl></w:abstractNum><w:num w:numId="1"><w:abstractNumId w:val="0"/></w:num></w:numbering>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);
    assert_opens_clean(
        &b,
        "ECMA-376 §17.9.28: CT_Lvl declares suff minOccurs=0 and an omitted suff defaults to tab; \
         a level with no suff element is well-formed and Word opens it without repair.",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted");
    assert_eq!(
        accepted.to_text().trim(),
        "Item one",
        "ECMA-376 §17.9.28: to_text() carries no synthesized marker/separator, so accept-all \
         reproduces the run text verbatim regardless of the level's (defaulted) suffix."
    );
}

