#[test]
fn islgl_explicit_false_off_opens_clean_body_intact() {
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>Roman item one</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>Roman item two</w:t></w:r></w:p><w:sectPr/>"#;
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="0"><w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="upperRoman"/><w:isLgl w:val="false"/><w:lvlText w:val="%1."/><w:lvlJc w:val="start"/></w:lvl></w:abstractNum><w:num w:numId="1"><w:abstractNumId w:val="0"/></w:num></w:numbering>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);
    assert_opens_clean(
        &b,
        "ECMA-376 §17.9.4 / §17.17.4: isLgl is a common boolean (CT_OnOff); val=\"false\" is a \
         schema-valid OnOff value that turns the legal toggle off, so the package is well-formed \
         and opens without repair.",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted");
    assert_eq!(
        accepted.to_text().trim(),
        "Roman item one\n\nRoman item two",
        "ECMA-376 §17.9.4: to_text() carries only run text (the marker is metadata), so accept-all \
         reproduces both run strings verbatim regardless of the OFF isLgl toggle."
    );
}

